head.script:
'use strict';

const ready = function () {

  const phases = ['System', 'UserOnce', 'FirstLogon', 'DefaultUser'];
  const searchParams = new URL(document.location).searchParams;
  const accountNames = document.querySelectorAll('input[name^="AccountName"]');
  const computerName = document.querySelector('input[name="ComputerName"]');

  const quote = function (value) {
    return `“${value}”`;
  };

  const formatScriptType = function (value) {
    return `.${value.toLowerCase()}`;
  };

  const checkXml = function (event, validations, xml) {
    if (xml === undefined) {
      xml = event.target.value;
    }
    const dom = new DOMParser().parseFromString(xml, 'application/xml');
    if (dom.querySelector('parsererror')) {
      return event.target.invalid('Your XML document is not well-formed.', event);
    }
    for (const validation of validations ?? []) {
      if (validation.test(dom) !== true) {
        return event.target.invalid(validation.message, event);
      }
    }
    return event.target.valid();
  };

  {
    const update = function (event) {
      for (const option of event.target.selectedOptions) {
        if (this.keyboard) {
          const data = option.dataset.keyboard;
          if (data) {
            this.keyboard.value = data;
          }
        }
        if (this.location) {
          const data = option.dataset.location;
          if (data) {
            this.location.value = data;
          }
        }
      }
    };

    document.querySelector('select[name="Locale"]').addEventListener('change', update.bind(
      {
        keyboard: document.querySelector('select[name="Keyboard"]'),
        location: document.querySelector('select[name="GeoLocation"]')
      }
    ));

    document.querySelector('select[name="Locale2"]').addEventListener('change', update.bind(
      {
        keyboard: document.querySelector('select[name="Keyboard2"]')
      }
    ));

    document.querySelector('select[name="Locale3"]').addEventListener('change', update.bind(
      {
        keyboard: document.querySelector('select[name="Keyboard3"]')
      }
    ));
  }
  {
    for (const elem of document.querySelectorAll('[data-required="true"]')) {
      elem.required = true;
    }
  }
  {
    const admins = document.querySelectorAll('select[name^="AccountGroup"], input[name="AutoLogonMode"][value="Builtin"]');

    const validate = function (event) {
      const hasAdmin = (function () {
        for (const admin of admins) {
          if (admin.type === 'select-one') {
            if (!admin.disabled) {
              if (admin.value === 'Administrators') {
                return true;
              }
            }
          }
          if (admin.type === 'radio') {
            if (admin.checked) {
              if (admin.value === 'Builtin') {
                return true;
              }
            }
          }
        }
        return false;
      })();
      for (const admin of admins) {
        if (hasAdmin) {
          admin.valid();
        } else {
          admin.invalid(`You must create at least one account in the ${quote('Administrators')} group or activate the built-in ${quote('Administrator')} account.`, event);
        }
      }
      {
        const keep = document.querySelector('input[name="KeepSensitiveFiles"]');
        const none = document.querySelector('input[name="AutoLogonMode"][value="None"]');
        if (keep.checked || !none.checked) {
          none.valid();
          keep.valid();
        } else {
          const message = 'To delete sensitive files, you must let Windows log on to an administrator account.';
          none.invalid(message, event);
          keep.invalid(message, event);
        }
      }
    };

    document.querySelectorAll('select[name^="AccountGroup"], input[name="AutoLogonMode"], input[name="KeepSensitiveFiles"]').onChange(validate);
  }
  {
    const validate = function (event) {
      for (const accountName of accountNames) {
        const result = (function () {

          const valid = function () {
            return {
              Valid: true
            };
          };

          const invalid = function (message = 'This account name is invalid.') {
            return {
              Valid: false,
              Message: message
            };
          }

          {
            if (accountName.value === '') {
              return valid();
            }
          }
          {
            if (accountName.value.trim() === '') {
              return invalid();
            }
          }
          {
            if (accountName.value !== accountName.value.trim()) {
              return invalid('Account name must not begin or end with whitespace character.');
            }
          }
          {
            if (accountName.value.length > 20) {
              return invalid('Account name must not be longer than 20 characters.');
            }
          }
          {
            const existing = [
              'administrator',
              'guest',
              'defaultaccount',
              'system',
              'network service',
              'local service',
              'none',
              'wdagutilityaccount'
            ];
            if (existing.includes(accountName.value.toLowerCase())) {
              return invalid('Account name is already used by existing Windows system account.');
            }
          }
          {
            if (document.querySelector('input[name="ComputerNameMode"]:checked').value === 'Custom') {
              if (computerName.value.toLowerCase() === accountName.value.toLowerCase()) {
                return invalid('Account name must not be the same as the computer name.');
              }
            }
          }
          {
            for (const other of accountNames) {
              if (other !== accountName) {
                if (other.value.toLowerCase() === accountName.value.toLowerCase()) {
                  return invalid('Account name is already used.');
                }
              }
            }
          }
          {
            const match = /\x2F|\x5C|\x5B|\x5D|\x3A|\x3B|\x7C|\x3D|\x2C|\x2B|\x2A|\x3F|\x3C|\x3E|\x22|\x25/.exec(accountName.value);
            if (match !== null) {
              return invalid(`Account name must not contain ${quote(match[0])} character.`);
            }
          }
          {
            if (accountName.value.endsWith('.')) {
              return invalid(`Account name must not end with ${quote('.')} character.`);
            }
          }
          return valid();
        })();

        if (result.Valid) {
          accountName.valid();
        } else {
          accountName.invalid(result.Message, event);
        }
      }
    };

    const join = function (event) {
      for (const accountName of accountNames) {
        const hasValue = accountName.value !== '';
        const tr = accountName.parentElement.parentElement;
        {
          const display = tr.querySelector(':scope input[name^="AccountDisplayName"]');
          display.disabled = !hasValue;
        }
        {
          const password = tr.querySelector(':scope input[name^="AccountPassword"]');
          password.disabled = !hasValue;
        }
        {
          const group = tr.querySelector(':scope select[name^="AccountGroup"]');
          group.disabled = !hasValue;
          group.change();
        }
      }
    };

    accountNames.onTextChanged(validate);
    accountNames.onTextChanged(join);
  }
  {
    const checkables = document.querySelectorAll('input[type="radio"], input[type="checkbox"]');
    const update = function (event) {
      for (const checkable of checkables) {
        for (const fieldset of checkable.parentElement.parentElement.querySelectorAll(":scope > fieldset")) {
          fieldset.disabled = !checkable.checked;
        }
      }
    };
    checkables.onChange(update);
  }
  {
    const elem = document.querySelector('select[name="ProcessorArchitecture"]');
    elem.addEventListener('change', (event) => {
      if (elem.selectedIndex === -1) {
        elem.invalid('You need to select at least one processor architecture.', event);
      } else {
        elem.valid();
      }
    });
  }
  {
    const duration = document.querySelector('input[name="LockoutDuration"]');
    const window = document.querySelector('input[name="LockoutWindow"]');

    const number = function (elem) {
      return parseInt(elem.value, 10);
    };

    const validate = function (event) {
      if (number(duration) >= number(window)) {
        duration.valid();
        window.valid();
      } else {
        const message = `Lockout window (${window.value}) must be less than or equal to lockout duration (${duration.value}).`;
        duration.invalid(message, event);
        window.invalid(message, event);
      }
    };

    duration.onTextChanged(validate);
    window.onTextChanged(validate);
  }
  {
    computerName.onTextChanged((event) => {
      const elem = event.target;

      const result = (function () {
        const valid = function () {
          return {
            Valid: true
          };
        };

        const invalid = function (message) {
          return {
            Valid: false,
            Message: message
          };
        }

        if (elem.value.trim() === '') {
          return invalid('Computer name must not be empty.');
        }
        {
          const match = /\s|\x7B|\x7C|\x7D|\x7E|\x5B|\x5C|\x5D|\x5E|\x27|\x3A|\x3B|\x3C|\x3D|\x3E|\x3F|\x40|\x21|\x22|\x23|\x24|\x25|\x60|\x28|\x29|\x2B|\x2F|\x2E|\x2C|\x2A|\x26/.exec(elem.value);
          if (match !== null) {
            return invalid(`Computer name must not contain character ${quote(match[0])}.`);
          }
        }
        if (/^[0-9]+$/.test(elem.value)) {
          return invalid('Computer name must not contain digits only.');
        }
        {
          if (document.querySelector('input[name="UserAccountMode"]:checked').value === 'Unattended') {
            for (const accountName of accountNames) {
              if (elem.value.toLowerCase() === accountName.value.toLowerCase()) {
                return invalid('Computer name must not be the same as a user account name.');
              }
            }
          }
        }
        return valid();
      })();

      if (result.Valid) {
        elem.valid();
      } else {
        elem.invalid(result.Message, event);
      }
    });
  }
  {
    const join = function (sources, targets) {
      const handler = function (event) {
        if (event.isTrusted) {
          for (const target of targets.querySelectorAll('input')) {
            target.change();
          }
        }
      }

      for (const source of sources.querySelectorAll('input')) {
        if (source.type === 'text') {
          source.onTextChanged(handler);
        } else {
          source.addEventListener('change', handler);
        }
      }
    };

    const userAccounts = document.querySelector('input[name="UserAccountMode"]').parentElement.parentElement;
    const computerName = document.querySelector('input[name="ComputerNameMode"]').parentElement.parentElement;

    join(userAccounts, computerName);
    join(computerName, userAccounts);
  }
  {
    const auth = document.querySelector('select[name="WifiAuthentication"]');
    const passwd = document.querySelector('input[name="WifiPassword"]');

    auth.addEventListener('change', (event) => {
      passwd.disabled = auth.value === 'Open';
    });
  }
  {
    const bloatwares = Array.from(document.querySelectorAll('.Bloatwares input'));

    const set = function (event) {
      for (const bloatware of bloatwares) {
        bloatware.checked = this.checked;
      }
      bloatwares[0].change();
    };
    {
      document.querySelector('#SelectAllBloatwares').addEventListener('click', set.bind({ checked: true }));
      document.querySelector('#DeselectAllBloatwares').addEventListener('click', set.bind({ checked: false }));
    }
    {
      const pins = document.querySelector('input[name="StartPinsMode"]').parentElement.parentElement;

      function wasChangedByUser() {
        pins.dataset.changedByUser = "true";
      }

      function setValue(value) {
        if (pins.dataset.changedByUser !== "true") {
          pins.querySelector(`input[value="${value}"]`).checked = true;
        }
      }
      {
        if (searchParams.has('StartPinsMode')) {
          wasChangedByUser();
        }
      }
      {
        for (const input of pins.querySelectorAll('input')) {
          input.addEventListener('change', (event) => {
            if (event.isTrusted) {
              wasChangedByUser();
            }
          });
        }
      }
      {
        for (const bloatware of bloatwares) {
          bloatware.addEventListener('change', (event) => {
            const newValue = bloatwares.some(b => b.checked) ? 'Empty' : 'Default';
            setValue(newValue);
          });
        }
      }
    }
  }
  {
    const setPlaceholder = function (event) {
      const placeholders = {
        'System': {
          'Cmd': 'powercfg.exe /HIBERNATE OFF',
          'Ps1': 'Set-MpPreference -DisableRealtimeMonitoring $true;',
          'Reg': 'Windows Registry Editor Version 5.00\r\n\r\n[HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Remote Assistance]\r\n"fAllowToGetHelp"=dword:00000000',
          'Vbs': 'WScript.Echo "Hello!"'
        },
        'FirstLogon': {
          'Cmd': 'setx.exe DIRCMD "/A /O:GN /C /N"',
          'Ps1': 'Set-WinHomeLocation -GeoId 94;',
          'Reg': 'Windows Registry Editor Version 5.00\r\n\r\n[HKEY_CURRENT_USER\\Control Panel\\Desktop]\r\n"ScreenSaverIsSecure"="1"',
          'Vbs': 'WScript.Echo "Hello!"'
        },
        'UserOnce': {
          'Cmd': 'setx.exe DIRCMD "/A /O:GN /C /N"',
          'Ps1': 'Set-WinHomeLocation -GeoId 94;',
          'Reg': 'Windows Registry Editor Version 5.00\r\n\r\n[HKEY_CURRENT_USER\\Control Panel\\Desktop]\r\n"ScreenSaverIsSecure"="1"',
          'Vbs': 'WScript.Echo "Hello!"'
        },
        'DefaultUser': {
          'Reg': 'Windows Registry Editor Version 5.00\r\n\r\n[HKEY_USERS\\DefaultUser\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced]\r\n"ShowTaskViewButton"=dword:00000000',
          'Cmd': 'reg.exe add "HKU\\DefaultUser\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced" /v "ShowTaskViewButton" /t REG_DWORD /d 0 /f',
          'Ps1': 'Set-ItemProperty -LiteralPath "Registry::HKU\\DefaultUser\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Advanced" -Name "ShowTaskViewButton" -Type "DWord" -Value 0;'
        }
      };
      const phase = event.target.dataset.phase;
      const type = event.target.value;
      const textarea = event.target.parentElement.querySelector('textarea');
      if (textarea) {
        textarea.placeholder = placeholders[phase][type];
      }
    };

    document.querySelectorAll('.Scripts select').onChange(setPlaceholder);
  }
  {
    const validate = function (event) {
      checkXml(event, [
        {
          test: (dom) => dom.documentElement.localName === 'AppLockerPolicy',
          message: 'The root element must be \u003cAppLockerPolicy\u003e…\u003c/AppLockerPolicy\u003e.'
        }
      ]);
    };

    document.querySelector('textarea[name="AppLockerPolicyXml"]').onTextChanged(validate);
  }
  {
    const validate = function (event) {
      checkXml(event, [
        {
          test: (dom) => dom.documentElement.localName === 'WLANProfile',
          message: 'The root element must be \u003cWLANProfile xmlns="http://www.microsoft.com/networking/WLAN/profile/v1"\u003e…\u003c/WLANProfile\u003e.'
        }
      ]);
    };

    document.querySelector('textarea[name="WifiProfileXml"]').onTextChanged(validate);
  }
  {
    const validate = function (event) {
      try {
        JSON.parse(event.target.value);
        event.target.valid();
      } catch (e) {
        event.target.invalid('This string is not valid JSON.', event);
      }
    };
    document.querySelector('textarea[name="StartPinsJson"]').onTextChanged(validate);
  }
  {
    const validate = function (event) {
      checkXml(event, []);
    };
    document.querySelector('textarea[name="StartTilesXml"]').onTextChanged(validate);
  }
  {
    const validate = function (event) {
      checkXml(event, []);
    };
    document.querySelector('textarea[name="TaskbarIconsXml"]').onTextChanged(validate);
  }
  {
    const handler = function (event) {
      const textarea = event.target.parentElement.querySelector('textarea');
      const select = event.target.parentElement.querySelector('select');

      (function () {
        const phase = (function () {
          for (const phase of phases) {
            if (textarea.name.startsWith(phase)) {
              return phase;
            }
          }
        })();

        if (textarea.value.trim() === '') {
          return textarea.valid();
        }

        if (select.value === 'Cmd') {
          if (phase !== 'UserOnce') {
            const match = /(^|\W)(set\s*\/p)/i.exec(textarea.value);
            if (match !== null) {
              return textarea.invalid(`You cannot prompt for user input (${quote(match[2])}) in .cmd scripts. Use a .ps1 script and the ${quote('Read-Host')} cmdlet instead.`, event);
            }
          }
        }

        return textarea.valid();
      })();
    };

    document.querySelectorAll('.Scripts textarea').onTextChanged(handler);
    document.querySelectorAll('.Scripts select').onChange(handler);
  }
  {
    const form = document.querySelector('form[method="get"]');
    {
      form.addEventListener('submit', (event) => {
        const params = new URLSearchParams(new FormData(event.target));
        if (params.toString().length > 0xFFFF) {
          event.preventDefault();
          window.alert('Your form submission exceeds the limits of this server. You need to shorten some of your inputs.');
        }
      });
    }
    {
      form.addEventListener('formdata', (event) => {
        const indexes = [...Array(99).keys()];
        const formData = event.formData;

        const deleteParamsIfFirstEmpty = function (keys) {
          const firstValue = formData.get(keys[0]);
          if (!firstValue || firstValue.trim() === '') {
            for (const key of keys) {
              formData.delete(key);
            }
          }
        };

        for (const index of indexes) {
          deleteParamsIfFirstEmpty([
            `AccountName${index}`,
            `AccountDisplayName${index}`,
            `AccountGroup${index}`,
            `AccountPassword${index}`
          ]);
          deleteParamsIfFirstEmpty([
            `Component${index}`,
            `ComponentContent${index}`
          ]);
          for (const phase of phases) {
            deleteParamsIfFirstEmpty([
              `${phase}Script${index}`,
              `${phase}ScriptType${index}`
            ]);
          }
        }
      });
    }
  }
  {
    const commands = ['active', 'add', 'assign', 'attributes', 'attach', 'automount', 'break', 'clean', 'compact', 'convert', 'create', 'delete', 'detail', 'detach', 'exit', 'extend', 'expand', 'filesystems', 'format', 'gpt', 'help', 'import', 'inactive', 'list', 'merge', 'online', 'offline', 'recover', 'rem', 'remove', 'repair', 'rescan', 'retain', 'san', 'select', 'setid', 'shrink', 'uniqueid'];

    const isCommand = function (token) {
      if (3 > token.length) {
        return false;
      }
      for (const command of commands) {
        if (command.startsWith(token)) {
          return true;
        }
      }
      return false;
    };

    document.querySelector('textarea[name="DiskpartScript"]').onTextChanged((event) => {
      const textarea = event.target;
      for (const line of textarea.value.split('\n').map((line) => line.trim())) {
        if (line === '') {
          continue;
        }
        const token = line.split(/\s+/)[0].toLowerCase();
        if (isCommand(token)) {
          continue;
        }
        textarea.invalid(`Your diskpart script appears to be invalid in line ${quote(line)}.`, event);
        return;
      }
      textarea.valid();
    });
  }
  {
    document.querySelector('textarea[name="DiskAssertionScript"]').onTextChanged((event) => {
      const textarea = event.target;
      for (const line of textarea.value.split('\n').map((line) => line.trim())) {
        if (line.length > 210) {
          textarea.invalid(`The line ${quote(line.substring(0, 50) + '…')} is too long. Add line breaks to make it shorter and consider using the line-continuation character ${quote('_')}.`, event);
          return;
        }
      }
      textarea.valid();
    });
  }
  {
    document.querySelector('textarea[name="ComputerNameScript"]').onTextChanged((event) => {
      const textarea = event.target;
      const forbidden = [
        'Restart-Computer',
        'Rename-Computer',
        'Stop-Computer'
      ];
      if (new RegExp(forbidden.join('|'), 'i').test(textarea.value)) {
        return textarea.invalid(`You must not call cmdlets ${forbidden.map(f => quote(f)).join(', ')} in this script.`, event);
      }
      return textarea.valid();
    });
  }
  {
    const hex = function (val) {
      return 'U+' + val.charCodeAt(0).toString(16).toUpperCase().padStart(4, '0');
    };

    const check = function (event) {
      if (event.target.validity.valid || event.target.validationMessage.indexOf('must not be used in XML documents') !== -1) {
        const match = /\x00|\x01|\x02|\x03|\x04|\x05|\x06|\x07|\x08|\x0B|\x0C|\x0E|\x0F|\x10|\x11|\x12|\x13|\x14|\x15|\x16|\x17|\x18|\x19|\x1A|\x1B|\x1C|\x1D|\x1E|\x1F/.exec(event.target.value);
        if (match === null) {
          event.target.valid();
        } else {
          event.target.invalid(`Character ${quote(hex(match[0]))} must not be used in XML documents.`, event);
        }
      }
    };
    document.querySelectorAll('textarea, input[type="text"]').onTextChanged(check);
  }
  {
    const validate = function (event) {
      checkXml(event, [
        {
          test: (dom) => dom.querySelector("settings, component") === null,
          message: `You must not include elements ${quote('settings')} or ${quote('component')} with your XML markup.`
        },
        {
          test: function (dom) {
            if (event.target.value.trim() === '') {
              return true;
            }

            for (const child of dom.documentElement.childNodes) {
              if (child.nodeType === Node.TEXT_NODE) {
                if (child.nodeValue.trim() !== '') {
                  return false;
                }
              }
            }

            return true;
          },
          message: 'Your XML markup must not contain top-level text nodes.'
        }
      ], `\u003Croot xmlns='urn:schemas-microsoft-com:unattend' xmlns:wcm='http://schemas.microsoft.com/WMIConfig/2002/State'\u003E${event.target.value}\u003C/root\u003E`);
    };
    document.querySelectorAll('textarea[name^="ComponentContent"]').onTextChanged(validate);
  }
  {
    const validate = function (event) {
      const result = (function () {

        if (document.querySelector('input[name="PartitionMode"][value="Custom"]').checked) {
          const script = document.querySelector('textarea[name="DiskpartScript"]').value.toLowerCase();

          const checkDriveLetterAssignment = function (letter, purpose) {
            if (new RegExp(`^\\s*ASSIGN\\s+LETTER(\\s+|(\\s*=\\s*))((${letter})|("${letter}"))\\s*$`, 'im').test(script)) {
              return {
                Valid: true
              };
            } else {
              return {
                Valid: false,
                Message: `Your diskpart script must contain a line such as ${quote('ASSIGN LETTER=' + letter)} to assign the drive letter ${quote(letter + ':')} to the ${purpose} partition.`
              };
            }
          };

          const checks = [
            checkDriveLetterAssignment('W', 'Windows'),
            checkDriveLetterAssignment('S', 'system')
          ];

          for (const check of checks) {
            if (!check.Valid) return check;
          }
        }

        return {
          Valid: true
        };

      })();

      if (result.Valid) {
        event.target.valid();
      } else {
        event.target.invalid(result.Message, event);
      }
    };

    document.querySelector('textarea[name="DiskpartScript"]').onTextChanged(validate);
  }
  {
    const genericEdition = document.querySelector('input[name="WindowsEditionMode"][value="Generic"]');
    const automaticFrom = document.querySelector('input[name="InstallFromMode"][value="Automatic"]');
    const peGenerated = document.querySelector('input[name="PEMode"][value="Generated"]');

    const validate = function (event) {
      if (genericEdition.checked || !automaticFrom.checked || !peGenerated.checked) {
        automaticFrom.valid();
      } else {
        const msg = `Cannot determine which Windows image to apply. Specify image by name or index.`;
        automaticFrom.invalid(msg, event);
      }
    };

    document.querySelectorAll('input[name="WindowsEditionMode"], input[name="InstallFromMode"], input[name="PEMode"]').onChange(validate);
  }
  {
    for (const input of document.querySelectorAll('input, textarea, select')) {
      input.change();
    }
    for (const name of ['Keyboard', 'GeoLocation', 'Keyboard2', 'Keyboard3']) {
      const value = searchParams.get(name);
      if (value) {
        const select = document.querySelector(`select[name="${name}"]`);
        if (select) {
          select.value = value;
        }
      }
    }
  }
  {
    const components = document.querySelectorAll('select[name^="Component"]');
    const validate = function (event) {
      for (const component of components) {
        const valid = (function () {
          if (component.value === '') {
            return true;
          }
          for (const other of components) {
            if (other === component) {
              continue;
            }
            if (other.value === component.value) {
              return false;
            }
          }
          return true;
        })();
        if (valid) {
          component.valid();
        } else {
          component.invalid(`You must not specify component ${quote(component.value)} more than once.`, event);
        }
      }
    };
    components.onChange(validate);
  }
};

HTMLElement.prototype.valid = function () {
  this.setCustomValidity('');
};

HTMLElement.prototype.invalid = function (message, event) {
  this.setCustomValidity(message);
  if (event.target === this) {
    if (event.isTrusted) {
      this.reportValidity();
    }
  }
};

HTMLElement.prototype.change = function () {
  this.dispatchEvent(new Event('change'));
};

HTMLElement.prototype.onTextChanged = function (callback) {
  for (const type of ['change', 'keyup', 'input', 'paste']) {
    this.addEventListener(type, callback);
  }
};

NodeList.prototype.onChange = function (callback) {
  for (const node of this) {
    node.addEventListener('change', callback);
  }
}

NodeList.prototype.onTextChanged = function (callback) {
  for (const node of this) {
    node.onTextChanged(callback);
  }
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', ready);
} else {
  ready();
}

